/**
 * Principia Metaphysica - Falsification page logic
 *
 * Loads AutoGenerated/parameters.json, resolves the ALP prediction
 * (m_a in meV, g_aγγ in GeV^-1), renders the live values into the
 * prediction block, draws the SVG sensitivity plot, and decides which
 * banner to display:
 *
 *   • BabyIAXO floor (2028): g_aγγ ≈ 1.5e-11 GeV^-1
 *   • IAXO floor   (2030+): g_aγγ ≈ 1.0e-12 GeV^-1
 *
 *   If g_aγγ ≥ BabyIAXO floor and m_a is in the helioscope window
 *   (10^-4 .. 10 eV  →  0.1 µeV .. 10 eV) → "FALSIFIABLE BY 2028".
 *   Otherwise → "outside reach, awaiting IAXO".
 *
 * Copyright (c) 2025-2026 Andrew Keith Watts. All rights reserved.
 */
(function () {
    'use strict';

    // ──────────────────────────────────────────────────────────────
    // Constants for sensitivity floors
    // ──────────────────────────────────────────────────────────────
    const BABYIAXO_FLOOR = 1.5e-11;   // GeV^-1   (Phase 1, 2028 reach)
    const IAXO_FLOOR     = 1.0e-12;   // GeV^-1   (Full IAXO, 2030+)
    const CAST_BOUND     = 6.6e-11;   // GeV^-1   (CAST 2017 upper limit)
    const STELLAR_BOUND  = 1.0e-10;   // GeV^-1   (HB stellar cooling)

    // Helioscope sensitivity window in m_a
    const HELIO_M_A_MIN_EV = 1e-4;    // 0.1 µeV
    const HELIO_M_A_MAX_EV = 10;      // 10  eV

    // ADMX cavity window (microwave)
    const ADMX_M_A_MIN_EV = 2e-6;     // 2 µeV
    const ADMX_M_A_MAX_EV = 4e-5;     // ~40 µeV

    // Default fallback values (used only if JSON load fails)
    const FALLBACK_M_A_MEV   = 3.51;
    const FALLBACK_G_AGG     = 2.9e-11;
    const SIGMA_FRAC         = 0.10;   // ±10 % 1σ band (visualisation)

    // ──────────────────────────────────────────────────────────────
    // Path resolution for AutoGenerated/parameters.json
    // ──────────────────────────────────────────────────────────────
    function candidatePaths() {
        return [
            '/AutoGenerated/parameters.json',
            '../AutoGenerated/parameters.json',
            'AutoGenerated/parameters.json',
            '../../AutoGenerated/parameters.json'
        ];
    }

    async function loadParameters() {
        for (const p of candidatePaths()) {
            try {
                const r = await fetch(p);
                if (r.ok) {
                    const json = await r.json();
                    console.log(`[pm-falsification] loaded parameters.json from ${p}`);
                    return json;
                }
            } catch (e) {
                // try next
            }
        }
        console.warn('[pm-falsification] could not load parameters.json — using fallback values');
        return null;
    }

    // ──────────────────────────────────────────────────────────────
    // Parameter extraction
    // ──────────────────────────────────────────────────────────────
    function pickParam(params, key) {
        if (!params) return null;
        const root = params.parameters || params;
        return root[key] || null;
    }

    function coerceNumber(v) {
        if (typeof v === 'number' && Number.isFinite(v)) return v;
        if (typeof v === 'string') {
            // Strip unicode superscripts/exponents — "10⁻¹¹" → 1e-11
            const SUP = '⁻⁺°¹²³⁴⁵⁶⁷⁸⁹';
            const isPureSup = v.length > 0 && [...v].every(c => SUP.includes(c) || c === '1' || c === '0');
            if (isPureSup) {
                // crude: any "⁻" → "-", digit-superscripts → digits
                const map = { '⁻': '-', '⁺': '+', '°': '0',
                              '¹': '1', '²': '2', '³': '3',
                              '⁴': '4', '⁵': '5', '⁶': '6',
                              '⁷': '7', '⁸': '8', '⁹': '9' };
                const exponent = [...v].map(c => map[c] || c).join('');
                if (v.includes('10') || v.length >= 3) {
                    const m = exponent.match(/^10([-+]?\d+)$/);
                    if (m) return Math.pow(10, parseInt(m[1], 10));
                }
            }
            // Try plain parse
            const n = parseFloat(v);
            if (Number.isFinite(n)) return n;
        }
        return null;
    }

    function extractPrediction(params) {
        // m_a in meV
        const massEntry = pickParam(params, 'alp.mass_meV');
        const couplingEntry = pickParam(params, 'alp.coupling_GeV_inv');

        let m_a_meV = coerceNumber(massEntry?.value);
        let g_agg   = coerceNumber(couplingEntry?.value);

        if (m_a_meV === null || !Number.isFinite(m_a_meV)) m_a_meV = FALLBACK_M_A_MEV;
        if (g_agg   === null || !Number.isFinite(g_agg))   g_agg   = FALLBACK_G_AGG;

        // parameters.json stores g_aγγ as the order-of-magnitude string "10⁻¹¹".
        // The high-precision central value 2.9e-11 GeV⁻¹ is documented in
        // simulations/PM/portals/alp_portals.py. Detect the order-of-magnitude
        // case (mantissa ≡ 1) and refine to the documented central value so the
        // sensitivity matrix and SVG plot reflect the actual prediction.
        if (typeof couplingEntry?.value === 'string') {
            const raw = couplingEntry.value;
            // Pure power-of-ten encoding has no decimal mantissa
            const isPowerOfTen = /^10[⁻⁺\-+]?[⁰¹²³⁴⁵⁶⁷⁸⁹0-9]+$/.test(raw);
            if (isPowerOfTen) {
                g_agg = FALLBACK_G_AGG;
            }
        }

        return {
            m_a_meV,
            m_a_eV: m_a_meV * 1e-3,
            g_agg,
            source: massEntry?.source_simulation || massEntry?.source || 'parameters.json',
            status: massEntry?.status || 'PREDICTED'
        };
    }

    // ──────────────────────────────────────────────────────────────
    // Banner decision logic
    // ──────────────────────────────────────────────────────────────
    function decideBanner(pred) {
        const inHelioWindow =
            pred.m_a_eV >= HELIO_M_A_MIN_EV &&
            pred.m_a_eV <= HELIO_M_A_MAX_EV;

        if (inHelioWindow && pred.g_agg >= BABYIAXO_FLOOR) {
            return {
                cls: 'banner-falsifiable',
                mark: '✓',
                text: 'FALSIFIABLE BY 2028 — BabyIAXO reaches this coupling at this mass'
            };
        }

        if (inHelioWindow && pred.g_agg >= IAXO_FLOOR) {
            return {
                cls: 'banner-awaiting',
                mark: '⚠',
                text: 'OUTSIDE BabyIAXO REACH — awaiting full IAXO (2030+) to probe this coupling'
            };
        }

        return {
            cls: 'banner-awaiting',
            mark: '⚠',
            text: 'Outside BabyIAXO / IAXO reach — requires next-generation helioscope'
        };
    }

    // ──────────────────────────────────────────────────────────────
    // DOM updates: prediction cells + placeholders
    // ──────────────────────────────────────────────────────────────
    function fmtSci(x, digits = 2) {
        if (!Number.isFinite(x)) return '—';
        return x.toExponential(digits);
    }

    function fmtSciPretty(x, digits = 2) {
        if (!Number.isFinite(x)) return '—';
        const s = x.toExponential(digits);
        // "2.90e-11" → "2.90 × 10⁻¹¹"
        const m = s.match(/^(-?\d+(?:\.\d+)?)e([-+]?\d+)$/);
        if (!m) return s;
        const mantissa = m[1];
        const expSign = m[2].startsWith('-') ? '⁻' : '';
        const expDigits = m[2].replace(/^[-+]/, '');
        const supMap = {'0':'⁰','1':'¹','2':'²','3':'³',
                        '4':'⁴','5':'⁵','6':'⁶','7':'⁷',
                        '8':'⁸','9':'⁹'};
        const sup = [...expDigits].map(c => supMap[c] || c).join('');
        return `${mantissa} × 10${expSign}${sup}`;
    }

    function updatePlaceholders(pred) {
        // data-pm-value placeholders specific to this page
        document.querySelectorAll('[data-pm-value="particle.axion_mass_meV"]').forEach(el => {
            el.textContent = pred.m_a_meV.toFixed(2);
            el.classList.add('pm-loaded');
            el.classList.remove('pm-loading', 'pm-error');
            el.classList.add('mathjax-ignore');
        });

        document.querySelectorAll('[data-pm-value="particle.g_a_gamma_gamma_GeV_inv"]').forEach(el => {
            el.textContent = fmtSciPretty(pred.g_agg, 2);
            el.classList.add('pm-loaded');
            el.classList.remove('pm-loading', 'pm-error');
            el.classList.add('mathjax-ignore');
        });

        const massCell = document.getElementById('fals-mass-value');
        if (massCell) massCell.textContent = pred.m_a_meV.toFixed(3);

        const couplingCell = document.getElementById('fals-coupling-value');
        if (couplingCell) couplingCell.textContent = fmtSciPretty(pred.g_agg, 2);

        const sourceCell = document.getElementById('fals-source');
        if (sourceCell) sourceCell.textContent = pred.source;

        const statusCell = document.getElementById('fals-status');
        if (statusCell) statusCell.textContent = pred.status;

        // Update sensitivity matrix prediction row dynamic cells
        const pRowMass = document.getElementById('row-prediction-mass');
        if (pRowMass) pRowMass.textContent = pred.m_a_meV.toFixed(2) + ' meV';

        const pRowG = document.getElementById('row-prediction-g');
        if (pRowG) pRowG.textContent = fmtSciPretty(pred.g_agg, 2) + ' GeV⁻¹';

        const pRowSigma = document.getElementById('row-prediction-sigma');
        if (pRowSigma) {
            const lo = pred.g_agg * (1 - SIGMA_FRAC);
            const hi = pred.g_agg * (1 + SIGMA_FRAC);
            pRowSigma.textContent = `${fmtSci(lo, 2)} – ${fmtSci(hi, 2)} (±10%)`;
        }
    }

    function updateBanner(banner) {
        const el = document.getElementById('fals-banner');
        if (!el) return;
        el.classList.remove('banner-loading', 'banner-falsifiable', 'banner-awaiting');
        el.classList.add(banner.cls);
        el.innerHTML =
            `<span class="banner-mark">${banner.mark}</span>` +
            `<span class="banner-text">${banner.text}</span>`;
    }

    // ──────────────────────────────────────────────────────────────
    // SVG plot: m_a (eV, log) vs g_aγγ (GeV^-1, log)
    // Plot range:
    //     x:  m_a in [1e-6, 1e1] eV  (microwave → helioscope band)
    //     y:  g_aγγ in [1e-13, 1e-9] GeV^-1
    // ──────────────────────────────────────────────────────────────
    function buildSVG(pred) {
        const svg = document.getElementById('fals-svg');
        if (!svg) return;

        // Clear existing
        while (svg.firstChild) svg.removeChild(svg.firstChild);

        const W = 800;
        const H = 480;
        const M = { left: 78, right: 22, top: 32, bottom: 60 };
        const plotW = W - M.left - M.right;
        const plotH = H - M.top - M.bottom;

        svg.setAttribute('viewBox', `0 0 ${W} ${H}`);
        svg.setAttribute('preserveAspectRatio', 'xMidYMid meet');
        svg.setAttribute('role', 'img');
        svg.setAttribute('aria-label',
            `Plot of axion mass versus photon coupling. PM prediction at m_a = ${pred.m_a_meV} meV, ` +
            `g_aγγ = ${pred.g_agg.toExponential(2)} GeV^-1.`);

        const SVG_NS = 'http://www.w3.org/2000/svg';
        const el = (tag, attrs = {}, parent = svg) => {
            const e = document.createElementNS(SVG_NS, tag);
            for (const [k, v] of Object.entries(attrs)) e.setAttribute(k, v);
            parent.appendChild(e);
            return e;
        };

        // ─── Defs: hatch pattern for BabyIAXO region ───
        const defs = el('defs');
        const pat = el('pattern', {
            id: 'babyiaxoHatch',
            patternUnits: 'userSpaceOnUse',
            width: 8, height: 8, patternTransform: 'rotate(45)'
        }, defs);
        el('rect', { width: 8, height: 8, fill: 'rgba(80,200,120,0.06)' }, pat);
        el('line', { x1: 0, y1: 0, x2: 0, y2: 8,
                     stroke: 'rgba(80,200,120,0.55)', 'stroke-width': 1.4 }, pat);

        // ─── Log-scale helpers ───
        // x: m_a in eV, log10 in [-6, 1]
        // y: g_aγγ in GeV^-1, log10 in [-13, -9]
        const X_LO = -6, X_HI = 1;
        const Y_LO = -13, Y_HI = -9;

        const xPx = (logE) => M.left + ((logE - X_LO) / (X_HI - X_LO)) * plotW;
        const yPx = (logG) => M.top + plotH - ((logG - Y_LO) / (Y_HI - Y_LO)) * plotH;

        // ─── Background ───
        el('rect', {
            x: M.left, y: M.top, width: plotW, height: plotH,
            fill: 'rgba(255,255,255,0.015)',
            stroke: 'rgba(255,255,255,0.18)', 'stroke-width': 1
        });

        // ─── Grid lines ───
        for (let lx = X_LO; lx <= X_HI; lx++) {
            const x = xPx(lx);
            el('line', { class: 'grid-line', x1: x, y1: M.top, x2: x, y2: M.top + plotH });
        }
        for (let ly = Y_LO; ly <= Y_HI; ly++) {
            const y = yPx(ly);
            el('line', { class: 'grid-line', x1: M.left, y1: y, x2: M.left + plotW, y2: y });
        }

        // ─── X-axis ticks & labels (log10) ───
        for (let lx = X_LO; lx <= X_HI; lx++) {
            const x = xPx(lx);
            el('line', { class: 'axis-line',
                         x1: x, y1: M.top + plotH, x2: x, y2: M.top + plotH + 5 });
            const t = el('text', { class: 'tick-label',
                                   x: x, y: M.top + plotH + 18,
                                   'text-anchor': 'middle' });
            t.textContent = `10${supStr(lx)}`;
        }
        // X-axis label
        const xLab = el('text', { class: 'axis-label',
                                  x: M.left + plotW / 2,
                                  y: M.top + plotH + 44,
                                  'text-anchor': 'middle' });
        xLab.textContent = 'm_a  (eV)';

        // ─── Y-axis ticks & labels ───
        for (let ly = Y_LO; ly <= Y_HI; ly++) {
            const y = yPx(ly);
            el('line', { class: 'axis-line',
                         x1: M.left - 5, y1: y, x2: M.left, y2: y });
            const t = el('text', { class: 'tick-label',
                                   x: M.left - 8, y: y + 4,
                                   'text-anchor': 'end' });
            t.textContent = `10${supStr(ly)}`;
        }
        // Y-axis label (rotated)
        const yLab = el('text', { class: 'axis-label',
                                  x: 18, y: M.top + plotH / 2,
                                  'text-anchor': 'middle',
                                  transform: `rotate(-90 18 ${M.top + plotH / 2})` });
        yLab.textContent = 'g_aγγ  (GeV⁻¹)';

        // ─── IAXO full reach region (g >= 1e-12 in helioscope window) ───
        const iaxoX1 = xPx(Math.log10(HELIO_M_A_MIN_EV));
        const iaxoX2 = xPx(Math.log10(HELIO_M_A_MAX_EV));
        const iaxoY1 = yPx(Math.log10(IAXO_FLOOR));
        el('rect', { class: 'iaxo-region',
                     x: iaxoX1, y: iaxoY1,
                     width: iaxoX2 - iaxoX1, height: M.top + plotH - iaxoY1 });

        // ─── BabyIAXO 2028 reach region (g >= 1.5e-11 in helioscope window) ───
        const babyY1 = yPx(Math.log10(BABYIAXO_FLOOR));
        el('rect', { class: 'babyiaxo-region',
                     x: iaxoX1, y: babyY1,
                     width: iaxoX2 - iaxoX1, height: M.top + plotH - babyY1 });

        // ─── CAST 2017 exclusion line ───
        const castY = yPx(Math.log10(CAST_BOUND));
        el('line', { class: 'grid-line',
                     x1: iaxoX1, y1: castY, x2: iaxoX2, y2: castY,
                     stroke: 'rgba(255,107,107,0.55)', 'stroke-width': 1.5,
                     'stroke-dasharray': '4 4' });
        const castLab = el('text', { class: 'annotation',
                                     x: iaxoX2 - 6, y: castY - 4,
                                     'text-anchor': 'end',
                                     fill: 'rgba(255,107,107,0.85)' });
        castLab.textContent = 'CAST 2017 (excluded above)';

        // ─── ADMX cavity band (different mass regime) ───
        const admxX1 = xPx(Math.log10(ADMX_M_A_MIN_EV));
        const admxX2 = xPx(Math.log10(ADMX_M_A_MAX_EV));
        el('rect', {
            x: admxX1, y: M.top, width: admxX2 - admxX1, height: plotH,
            fill: 'rgba(255,126,182,0.05)',
            stroke: 'rgba(255,126,182,0.4)', 'stroke-width': 1,
            'stroke-dasharray': '2 3'
        });
        const admxLab = el('text', { class: 'annotation',
                                     x: (admxX1 + admxX2) / 2, y: M.top + 14,
                                     'text-anchor': 'middle',
                                     fill: 'rgba(255,126,182,0.85)' });
        admxLab.textContent = 'ADMX (wrong m_a)';

        // ─── PM prediction point with ±10 % errorbar in g ───
        const logMa = Math.log10(pred.m_a_eV);
        const logG  = Math.log10(pred.g_agg);
        const logGlo = Math.log10(pred.g_agg * (1 - SIGMA_FRAC));
        const logGhi = Math.log10(pred.g_agg * (1 + SIGMA_FRAC));

        const px = xPx(logMa);
        const pyMid = yPx(logG);
        const pyLo  = yPx(logGlo);
        const pyHi  = yPx(logGhi);

        // Errorbar
        el('line', { class: 'prediction-errorbar', x1: px, y1: pyHi, x2: px, y2: pyLo });
        el('line', { class: 'prediction-errorbar', x1: px - 5, y1: pyHi, x2: px + 5, y2: pyHi });
        el('line', { class: 'prediction-errorbar', x1: px - 5, y1: pyLo, x2: px + 5, y2: pyLo });
        // Point
        el('circle', { class: 'prediction-point', cx: px, cy: pyMid, r: 6 });

        // Annotation arrow + label for the PM point
        const annX = Math.min(px + 90, M.left + plotW - 20);
        const annY = Math.max(pyMid - 30, M.top + 14);
        el('line', {
            x1: px + 8, y1: pyMid - 4,
            x2: annX - 4, y2: annY + 6,
            stroke: 'rgba(255,107,157,0.7)', 'stroke-width': 1.2
        });
        const annLab = el('text', { class: 'annotation',
                                    x: annX, y: annY,
                                    'text-anchor': 'start',
                                    fill: '#ff6b9d', 'font-weight': 600 });
        annLab.textContent =
            `PM: m_a = ${pred.m_a_meV.toFixed(2)} meV, g = ${fmtSciPretty(pred.g_agg, 1)}`;

        // ─── Legend (top-left of plot) ───
        const legendX = M.left + 14;
        const legendY = M.top + 14;

        const legendItems = [
            { swatchType: 'hatch', text: `BabyIAXO 2028 reach (g ≥ ${fmtSciPretty(BABYIAXO_FLOOR, 1)})` },
            { swatchType: 'iaxo',  text: `IAXO 2030+ reach (g ≥ ${fmtSciPretty(IAXO_FLOOR, 1)})` },
            { swatchType: 'point', text: 'PM prediction (±10% band)' }
        ];

        legendItems.forEach((item, i) => {
            const ly = legendY + i * 18;
            if (item.swatchType === 'hatch') {
                el('rect', { x: legendX, y: ly - 9, width: 22, height: 11,
                             fill: 'url(#babyiaxoHatch)',
                             stroke: 'rgba(80,200,120,0.85)', 'stroke-width': 1,
                             'stroke-dasharray': '2 2' });
            } else if (item.swatchType === 'iaxo') {
                el('rect', { x: legendX, y: ly - 9, width: 22, height: 11,
                             fill: 'rgba(139,127,255,0.10)',
                             stroke: 'rgba(139,127,255,0.7)', 'stroke-width': 1,
                             'stroke-dasharray': '2 2' });
            } else {
                el('circle', { cx: legendX + 11, cy: ly - 3, r: 5,
                               fill: '#ff6b9d', stroke: 'white', 'stroke-width': 1.5 });
            }
            const txt = el('text', { class: 'legend-text',
                                     x: legendX + 30, y: ly });
            txt.textContent = item.text;
        });
    }

    function supStr(n) {
        const map = {'-': '⁻', '+': '⁺',
                     '0':'⁰','1':'¹','2':'²','3':'³',
                     '4':'⁴','5':'⁵','6':'⁶','7':'⁷',
                     '8':'⁸','9':'⁹'};
        return String(n).split('').map(c => map[c] || c).join('');
    }

    // ──────────────────────────────────────────────────────────────
    // Entry point
    // ──────────────────────────────────────────────────────────────
    async function init() {
        const params = await loadParameters();
        const pred = extractPrediction(params);
        const banner = decideBanner(pred);

        updatePlaceholders(pred);
        updateBanner(banner);
        buildSVG(pred);

        console.log('[pm-falsification] prediction:', pred);
        console.log('[pm-falsification] banner:', banner);
    }

    if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', init);
    } else {
        init();
    }
})();
